import { t as prisma } from "../../../../chunks/prisma.js";
//#region src/routes/(app)/projects/+page.server.ts
var load = async ({ setHeaders }) => {
	setHeaders({ "Cache-Control": "public, max-age=300" });
	return { projects: await prisma.project.findMany({ orderBy: [
		{ featured: "desc" },
		{ order: "asc" },
		{ createdAt: "desc" }
	] }) };
};
//#endregion
export { load };
